import software.amazon.awssdk.auth.credentials.{AwsBasicCredentials, AwsCredentialsProvider, EnvironmentVariableCredentialsProvider}
import software.amazon.awssdk.regions.Region
import software.amazon.awssdk.services.s3.{S3Client, S3Configuration}
import software.amazon.awssdk.services.s3.model.{ListBucketsRequest, ListBucketsResponse}

object AwsService {
  private val region: Region = Region.US_EAST_1

  private val credentialsProvider: AwsCredentialsProvider = EnvironmentVariableCredentialsProvider.create()

  private val s3Client: S3Client = S3Client.builder()
    .region(region)
    .credentialsProvider(credentialsProvider)
    .serviceConfiguration(S3Configuration.builder().build())
    .build()

  def listBuckets(): ListBucketsResponse = {
    val listBucketsRequest = ListBucketsRequest.builder().build()
    s3Client.listBuckets(listBucketsRequest)
  }
}

object MainApp extends App {
  val response = AwsService.listBuckets()
  response.buckets().forEach(bucket => println(bucket.name()))
}